    """DB 저장 — 세션 upsert + 사용자/어시스턴트 메시지 insert."""
    try:
        session_obj = None
        if request.session_id:
            existing = await db.execute(
                select(TutorSession).where(TutorSession.session_uuid == uuid.UUID(request.session_id))
            )
            session_obj = existing.scalar_one_or_none()

        if not session_obj:
            session_obj = TutorSession(
                session_uuid=uuid.UUID(session_uuid_str),
                user_id=user_id,
                context_type=request.context_type,
                context_id=request.context_id,
                title=request.message[:50],
                message_count=0,
            )
            db.add(session_obj)
            await db.flush()

        cover_meta = _extract_session_cover_meta(request, assistant_content)
        if cover_meta.get("title"):
            session_obj.title = cover_meta["title"]
        elif not session_obj.title:
            session_obj.title = request.message[:50]
        if cover_meta.get("cover_icon_key"):
            session_obj.cover_icon_key = cover_meta["cover_icon_key"]
        if cover_meta.get("summary_keywords"):
            session_obj.summary_keywords = cover_meta["summary_keywords"]
        if cover_meta.get("summary_snippet"):
            session_obj.summary_snippet = cover_meta["summary_snippet"]

        db.add(TutorMessage(
            session_id=session_obj.id,
            role="user",
            content=request.message,
            message_type="text",
        ))
        db.add(TutorMessage(
            session_id=session_obj.id,
            role="assistant",
            content=assistant_content,
            message_type="text",
        ))

        session_obj.message_count = (session_obj.message_count or 0) + 2
        session_obj.last_message_at = datetime.utcnow()
        await db.commit()

        # Redis 세션 캐시 무효화
        try:
            cache = await get_redis_cache()
            await cache.delete(f"tutor_session:{session_uuid_str}")
            await cache.delete(f"tutor_sessions_list:{user_id}")
        except Exception:
            pass  # 캐시 무효화 실패해도 DB는 이미 저장됨

        # 5턴마다 대화 요약 갱신
        if session_obj.message_count and session_obj.message_count % 5 == 0:
            try:
                recent_msgs = await db.execute(
                    select(TutorMessage)
                    .where(TutorMessage.session_id == session_obj.id)
                    .order_by(TutorMessage.created_at.desc())
                    .limit(20)
                )
                msgs_for_summary = list(reversed(recent_msgs.scalars().all()))
                summary_text = "\n".join(
                    f"{'사용자' if m.role == 'user' else 'AI'}: {m.content[:300]}"
                    for m in msgs_for_summary
                )

                settings = get_settings()
                if settings.OPENAI_API_KEY:
                    client = AsyncOpenAI(api_key=settings.OPENAI_API_KEY)
                    summary_resp = await client.chat.completions.create(
                        model="gpt-4o-mini",
                        temperature=0.2,
                        max_tokens=300,
                        messages=[
                            {"role": "system", "content": "아래 대화를 5문장 이내로 핵심만 요약하세요. 다룬 종목명/개념은 반드시 포함하세요."},
                            {"role": "user", "content": summary_text},
                        ],
                    )
                    session_obj.conversation_summary = summary_resp.choices[0].message.content

                    # 엔티티 추출 (간단)
                    existing_entities = session_obj.context_entities or []
                    # 종목명/코드 패턴
                    new_entities = re.findall(r'[가-힣]{2,10}(?:전자|바이오|제약|화학|건설|증권|은행|보험|카드|통신|에너지)', summary_text)
                    new_entities += re.findall(r'\b\d{6}\b', summary_text)
                    all_entities = list(dict.fromkeys(existing_entities + new_entities))[:30]
                    session_obj.context_entities = all_entities

                    await db.commit()
            except Exception as e:
                logger.warning("대화 요약 갱신 실패: %s", e)
    except Exception as e:
        logger.warning("Failed to save tutor session: %s", e)


async def generate_tutor_response(
    request: TutorChatRequest,
    db: AsyncSession,
    http_request: Request,
    current_user: Optional[dict] = None,
) -> AsyncGenerator[str, None]:
    """Generate streaming response for AI tutor."""

    session_id = request.session_id or str(uuid.uuid4())
    user_id = current_user["id"] if current_user else None
    settings = get_settings()
    guardrail_policy = (settings.TUTOR_GUARDRAIL_POLICY or "soft").strip().lower()
    if guardrail_policy not in {"strict", "soft"}:
        guardrail_policy = "soft"
    guardrail_decision = "SAFE"

    yield f"event: step\ndata: {json.dumps({'type': 'thinking', 'content': '질문을 분석하고 있습니다...'})}\n\n"

    # 가드레일 검사
    try:
        guardrail_result = await run_guardrail(request.message, policy=guardrail_policy)
        guardrail_decision = guardrail_result.decision

        if guardrail_result.hard_block:
            # 차단 메시지를 스트리밍으로 전송 후 즉시 종료 (DB 저장 없음)
            yield f"event: text_delta\ndata: {json.dumps({'content': guardrail_result.block_message})}\n\n"
            yield f"event: done\ndata: {json.dumps({'type': 'done', 'session_id': session_id, 'total_tokens': 0, 'guardrail_decision': guardrail_result.decision, 'guardrail_mode': guardrail_result.mode, 'response_mode': request.response_mode or 'plain', 'search_used': False})}\n\n"
            return
        if guardrail_result.soft_notice:
            yield f"event: step\ndata: {json.dumps({'type': 'guardrail_notice', 'content': guardrail_result.soft_notice, 'guardrail_decision': guardrail_result.decision, 'guardrail_mode': guardrail_result.mode})}\n\n"
    except Exception as e:
        logger.warning("Guardrail check failed, falling open: %s", type(e).__name__)

    api_key = settings.OPENAI_API_KEY
    if not api_key:
        yield f"event: error\ndata: {json.dumps({'type': 'error', 'error': 'OpenAI API key not configured'})}\n\n"
        return

    # 컨텍스트 수집
    page_context, sources, detected_stocks, chart_data, extra_context = await _collect_context(
        request, db, user_id
    )

    # 컨텍스트 envelope 파싱 (액션 추천용)
    context_envelope = None
    context_mode_for_actions = ""
    if request.context_text:
        try:
            _parsed_ctx = json.loads(request.context_text)
            if isinstance(_parsed_ctx, dict):
                context_envelope = _parsed_ctx
                context_mode_for_actions = str(
                    _parsed_ctx.get("mode")
                    or _parsed_ctx.get("interaction_state", {}).get("mode")
                    or ""
                ).strip()
        except (json.JSONDecodeError, AttributeError):
            pass

    # LLM 메시지 배열 구성
    messages = await _build_llm_messages(
        request,
        db,
        page_context,
        extra_context,
        guardrail_decision=guardrail_decision,
        guardrail_mode=guardrail_policy,
    )

    try:
        client = AsyncOpenAI(api_key=api_key)
        chat_model = settings.TUTOR_CHAT_MODEL or "gpt-5-mini"
        reasoning_effort = _normalize_reasoning_effort(settings.TUTOR_REASONING_EFFORT)
        response_mode = request.response_mode or "plain"
        use_web_search = bool(request.use_web_search)

        total_tokens = 0
        full_response = ""
        search_used = False
        used_responses_api = False
        stream_start = time.monotonic()
        chunk_count = 0

        _chat_ctx = None
        if _HAS_LANGSMITH:
            _chat_metadata = create_run_metadata(
                user_id=str(user_id) if user_id else None,
                session_id=session_id,
                module_name="tutor",
                model=chat_model,
            )
            _chat_ctx = trace_context(
                name="tutor_chat_llm",
                tags=["tutor", "chat"],
                metadata=_chat_metadata,
            )
            _chat_ctx.__enter__()

        if settings.TUTOR_USE_RESPONSES_API:
            response_input = [{"role": item["role"], "content": item["content"]} for item in messages]
            responses_kwargs: dict[str, Any] = {
                "model": chat_model,
                "input": response_input,
                "stream": True,
                "max_output_tokens": 4096,
            }

            if reasoning_effort:
                responses_kwargs["reasoning"] = {"effort": reasoning_effort}

            if use_web_search:
                responses_kwargs["tools"] = [{"type": "web_search_preview"}]

            try:
                responses_stream = await client.responses.create(**responses_kwargs)
                used_responses_api = True

                async for event in responses_stream:
                    chunk_count += 1

                    if chunk_count % 10 == 0:
                        if time.monotonic() - stream_start > 300:
                            logger.warning("Responses SSE 스트리밍 타임아웃 (300초 초과)")
                            yield f"event: error\ndata: {json.dumps({'type': 'error', 'error': 'Stream timeout'})}\n\n"
                            break
                        if await http_request.is_disconnected():
                            logger.info("클라이언트 연결 해제 감지, 스트리밍 중단")
                            break

                    event_data = _event_to_dict(event)
                    event_type = (event_data.get("type") or getattr(event, "type", "") or "").strip()

                    if event_type == "response.output_text.delta":
                        delta = event_data.get("delta") or getattr(event, "delta", "")
                        if isinstance(delta, str) and delta:
                            full_response += delta
                            yield f"event: text_delta\ndata: {json.dumps({'content': delta})}\n\n"
                        continue

                    if "web_search" in event_type:
                        search_used = True
                        yield f"event: step\ndata: {json.dumps({'type': 'tool_call', 'tool': 'web_search', 'content': '웹 검색 컨텍스트를 수집 중입니다.'})}\n\n"
                        continue

                    if "tool" in event_type and event_type not in {"response.output_text.annotation.added"}:
                        tool_name = "tool"
                        if "web_search" in event_type:
                            tool_name = "web_search"
                            search_used = True
                        yield f"event: step\ndata: {json.dumps({'type': 'tool_call', 'tool': tool_name, 'content': '도구 실행 중입니다.'})}\n\n"
                        continue

                    if event_type in {"response.error", "error"}:
                        error_obj = event_data.get("error") or {}
                        if isinstance(error_obj, dict):
                            err_message = error_obj.get("message") or str(error_obj)
                        else:
                            err_message = str(error_obj)
                        raise RuntimeError(err_message or "Responses API stream error")

                    if event_type == "response.completed":
                        response_payload = event_data.get("response") or {}
                        if isinstance(response_payload, dict):
                            total_tokens = _extract_usage_total(response_payload)
                            if not full_response:
                                extracted_text = _extract_response_text(response_payload)
                                if extracted_text:
                                    full_response = extracted_text
                                    yield f"event: text_delta\ndata: {json.dumps({'content': extracted_text})}\n\n"
                        continue
            except Exception as responses_err:
                logger.warning(
                    "responses_api_fallback model=%s reason=%s",
                    chat_model,
                    type(responses_err).__name__,
                )
                used_responses_api = False
                total_tokens = 0
                full_response = ""
                search_used = False

        if not used_responses_api:
            completion_kwargs = {
                "model": chat_model,
                "messages": messages,
                "max_tokens": 4096,
                "stream": True,
            }

            if reasoning_effort:
                try:
                    response = await client.chat.completions.create(
                        **completion_kwargs,
                        reasoning_effort=reasoning_effort,
                    )
                except Exception as e:
                    logger.warning(
                        "reasoning_effort fallback model=%s effort=%s reason=%s",
                        chat_model,
                        reasoning_effort,
                        type(e).__name__,
                    )
                    response = await client.chat.completions.create(**completion_kwargs)
                    reasoning_effort = ""
            else:
                response = await client.chat.completions.create(**completion_kwargs)

            if use_web_search:
                yield f"event: step\ndata: {json.dumps({'type': 'tool_call', 'tool': 'web_search', 'content': '현재 모델 경로에서는 웹 검색 도구를 지원하지 않아 기본 분석으로 진행합니다.'})}\n\n"

            async for chunk in response:
                chunk_count += 1

                if chunk_count % 10 == 0:
                    if time.monotonic() - stream_start > 300:
                        logger.warning("SSE 스트리밍 타임아웃 (300초 초과)")
                        yield f"event: error\ndata: {json.dumps({'type': 'error', 'error': 'Stream timeout'})}\n\n"
                        break
                    if await http_request.is_disconnected():
                        logger.info("클라이언트 연결 해제 감지, 스트리밍 중단")
                        break

                if chunk.choices and chunk.choices[0].delta.content:
                    content = chunk.choices[0].delta.content
                    full_response += content
                    yield f"event: text_delta\ndata: {json.dumps({'content': content})}\n\n"

                if chunk.usage:
                    total_tokens = chunk.usage.total_tokens

        # LangSmith 트레이스 종료
        if _chat_ctx:
            try:
                _chat_ctx.__exit__(None, None, None)
            except Exception:
                pass
            _chat_ctx = None

        # DB 저장
        await _save_tutor_session(db, session_id, user_id, request, full_response)

        # 시각화 자동 감지: should_auto_visualize() + chart_data 존재 여부로 판단
        from app.services.stock_resolver import should_auto_visualize
        should_viz = should_auto_visualize(request.message, bool(detected_stocks))
        # chart_data가 이미 수집되어 있으면 자동 시각화
        if chart_data and not should_viz:
            should_viz = True

        if should_viz and full_response:
            try:
                from app.services.tutor_chart_generator import generate_tutor_chart

                viz_chart = await generate_tutor_chart(
                    chart_data=chart_data,
                    full_response=full_response,
                    user_message=request.message,
                )
                if viz_chart and viz_chart.get("data"):
                    yield f"event: visualization\ndata: {json.dumps({'type': 'visualization', 'format': 'json', 'chartData': viz_chart})}\n\n"
            except Exception as viz_err:
                logger.warning("시각화 생성 실패: %s", viz_err)

        structured = None
        if request.structured_extract and request.response_mode == "canvas_markdown":
            structured = _extract_structured_from_markdown(full_response)

        if bool(search_used and use_web_search):
            sources.append(
                {
                    "type": "web",
                    "source_kind": "web",
                    "title": "웹 검색 보강 근거",
                    "url": "",
                    "content": "OpenAI web_search로 최신 웹 근거를 보강했습니다.",
                    "is_reachable": None,
                }
            )

        if sources:
            sources = await annotate_reachable_links(sources)

        done_data = {'session_id': session_id, 'total_tokens': total_tokens}
        done_data['type'] = 'done'
        done_data['model'] = chat_model
        done_data['search_used'] = bool(search_used and use_web_search)
        done_data['response_mode'] = response_mode
        done_data['guardrail_decision'] = guardrail_decision
        done_data['guardrail_mode'] = guardrail_policy
        if reasoning_effort:
            done_data['reasoning_effort'] = reasoning_effort
        if sources:
            done_data['sources'] = sources
        if structured:
            done_data['structured'] = structured

        recommended_actions = _recommend_actions(
            full_response, context_mode_for_actions, context_envelope
        )
        if recommended_actions:
            done_data['actions'] = recommended_actions

        yield f"event: done\ndata: {json.dumps(done_data)}\n\n"

    except asyncio.TimeoutError:
        logger.warning("OpenAI API 호출 타임아웃")
        if _chat_ctx:
            try:
                _chat_ctx.__exit__(None, None, None)
            except Exception:
                pass
        yield f"event: error\ndata: {json.dumps({'type': 'error', 'error': 'AI 응답 시간 초과'})}\n\n"
    except Exception as e:
        if _chat_ctx:
            try:
                _chat_ctx.__exit__(None, None, None)
            except Exception:
                pass
        yield f"event: error\ndata: {json.dumps({'type': 'error', 'error': str(e)})}\n\n"
    finally:
        # DB 세션 및 리소스 정리
        try:
            await db.close()
        except Exception:
            pass
        logger.debug("SSE 스트리밍 리소스 정리 완료 (session=%s)", session_id)


@router.post("/chat")
@limiter.limit("10/minute")
async def tutor_chat(
    request: Request,
    chat_request: TutorChatRequest,
    db: AsyncSession = Depends(get_db),
    current_user: Optional[dict] = Depends(get_current_user_optional),
) -> StreamingResponse:
    """AI Tutor chat endpoint with SSE streaming."""
    return StreamingResponse(
        generate_tutor_response(chat_request, db, request, current_user),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache",
            "Connection": "keep-alive",
            "X-Accel-Buffering": "no",
        },
    )

import { useCallback, useEffect, useMemo, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { API_BASE_URL, authFetch } from '../../api/client';
import { useTutor, useTutorUI } from '../../contexts';
import ActionConfirmDialog from './ActionConfirmDialog';
import AgentControlPulse from './AgentControlPulse';
import SlashCommandMenu, { SLASH_COMMANDS } from './SlashCommandMenu';
import useAgentPromptHints from '../../hooks/useAgentPromptHints';
import useAgentControlOrchestrator from '../../hooks/useAgentControlOrchestrator';
import useKeyboardInset from '../../hooks/useKeyboardInset';
import buildUiSnapshot from '../../utils/agent/buildUiSnapshot';
import buildActionCatalog from '../../utils/agent/buildActionCatalog';

function readSessionJson(key) {
  try {
    const raw = sessionStorage.getItem(key);
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
}

function getVisibleSectionsByMode(mode) {
  if (mode === 'stock') return ['portfolio_summary', 'holdings', 'stock_detail'];
  if (mode === 'education') return ['calendar', 'daily_briefing', 'quiz_mission'];
  if (mode === 'my') return ['profile', 'settings'];
  return ['asset_summary', 'learning_schedule', 'issue_card', 'conversation_cards'];
}

const SEARCH_TOGGLE_KEY = 'adelie_agent_web_search';

function readSearchToggle(mode) {
  try {
    const value = localStorage.getItem(SEARCH_TOGGLE_KEY);
    if (value === '1') return true;
    if (value === '0') return false;
    return mode === 'stock';
  } catch {
    return mode === 'stock';
  }
}

export default function AgentDock() {
  const { shouldHide, mode, placeholder, suggestedPrompt } = useAgentPromptHints();
  const [input, setInput] = useState('');
  const [inlineMessage, setInlineMessage] = useState(null);
  const [isRouting, setIsRouting] = useState(false);
  const [searchEnabled, setSearchEnabled] = useState(() => readSearchToggle(mode));
  const [showSlashMenu, setShowSlashMenu] = useState(false);
  const [slashQuery, setSlashQuery] = useState('');
  const [activePrefix, setActivePrefix] = useState(null);
  const location = useLocation();
  const navigate = useNavigate();
  const { messages, agentStatus, isStreamingActive } = useTutor();
  const { openTutor } = useTutorUI();
  const { keyboardOffset, shouldHideBottomNav } = useKeyboardInset();
  const hasActiveSession = Array.isArray(messages) && messages.length > 0;
  const isAgentRoute = location.pathname.startsWith('/agent');
  const hideBottomNav = shouldHideBottomNav;

  useEffect(() => {
    try {
      localStorage.setItem(SEARCH_TOGGLE_KEY, searchEnabled ? '1' : '0');
    } catch {
      // ignore storage errors
    }
  }, [searchEnabled]);

  useEffect(() => {
    try {
      const hasStoredValue = localStorage.getItem(SEARCH_TOGGLE_KEY);
      if (hasStoredValue === null) {
        setSearchEnabled(mode === 'stock');
      }
    } catch {
      setSearchEnabled(mode === 'stock');
    }
  }, [mode]);

  useEffect(() => {
    document.documentElement.style.setProperty('--keyboard-offset', `${keyboardOffset}px`);
    return () => {
      document.documentElement.style.setProperty('--keyboard-offset', '0px');
    };
  }, [keyboardOffset]);

  const baseContextPayload = useMemo(() => {
    if (mode === 'stock' && location.state?.stockContext) {
      return location.state.stockContext;
    }

    if (mode === 'home') {
      return readSessionJson('adelie_home_context');
    }

    if (mode === 'education') {
      return readSessionJson('adelie_education_context');
    }

    return null;
  }, [location.state, mode]);

  const {
    controlState,
    isAgentControlling,
    actionCatalog: orchestratorActionCatalog,
    executeAction,
    pendingAction,
    confirmPendingAction,
  } = useAgentControlOrchestrator({
    mode,
    stockContext: baseContextPayload,
  });

  const actionCatalog = useMemo(
    () => buildActionCatalog({ pathname: location.pathname, mode, stockContext: baseContextPayload }),
    [baseContextPayload, location.pathname, mode],
  );

  const buildControlContextPayload = useCallback((prompt = '') => {
    const uiSnapshot = buildUiSnapshot({
      pathname: location.pathname,
      mode,
      locationState: location.state || null,
      visibleSections: getVisibleSectionsByMode(mode),
      selectedEntities: {
        stock_code: baseContextPayload?.stock_code || null,
        stock_name: baseContextPayload?.stock_name || null,
        date_key: baseContextPayload?.date || null,
        case_id: baseContextPayload?.case_id || null,
      },
      filters: {
        tab: location.pathname.startsWith('/portfolio') ? 'portfolio' : mode,
      },
      portfolioSummary: baseContextPayload?.portfolio_summary || null,
    });

    return {
      ...(baseContextPayload || {}),
      ui_snapshot: uiSnapshot,
      action_catalog: actionCatalog,
      interaction_state: {
        source: 'agent_dock',
        mode,
        route: location.pathname,
        last_prompt: prompt || null,
        search_enabled: searchEnabled,
        control_phase: controlState.phase,
        control_active: isAgentControlling,
      },
    };
  }, [actionCatalog, baseContextPayload, controlState.phase, isAgentControlling, location.pathname, location.state, mode, searchEnabled]);

  const handleSlashCommand = useCallback((command) => {
    setShowSlashMenu(false);
    setSlashQuery('');

    const action = command.action;
    if (action.type === 'navigate') {
      navigate(action.path, action.tab ? { state: { tab: action.tab } } : undefined);
    } else if (action.type === 'action') {
      const matchedAction = orchestratorActionCatalog.find((item) => item.id === action.actionId);
      if (matchedAction) {
        executeAction(matchedAction, { contextPayload: buildControlContextPayload('') });
      } else {
        setInlineMessage({ text: '현재 화면에서 사용할 수 없는 명령이에요.', canvasPrompt: null });
      }
    } else if (action.type === 'param') {
      if (action.prefix) {
        setActivePrefix({ label: command.desc, prefix: action.prefix });
        setInput('');
      }
      if (action.key === 'use_web_search') {
        setSearchEnabled(true);
      }
    }
  }, [navigate, orchestratorActionCatalog, executeAction, buildControlContextPayload]);

  const submitPromptToCanvas = useCallback((prompt) => {
    const payload = buildControlContextPayload(prompt);

    navigate('/agent', {
      state: {
        mode,
        initialPrompt: prompt.trim(),
        contextPayload: payload,
        useWebSearch: searchEnabled,
        resetConversation: location.pathname !== '/agent',
      },
    });
  }, [buildControlContextPayload, location.pathname, mode, navigate, searchEnabled]);

  const routePrompt = useCallback(async (prompt, payload) => {
    const response = await authFetch(`${API_BASE_URL}/api/v1/tutor/route`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        message: prompt,
        mode,
        context_text: JSON.stringify(payload),
        ui_snapshot: payload.ui_snapshot || null,
        action_catalog: payload.action_catalog || [],
        interaction_state: payload.interaction_state || null,
      }),
    });
    if (!response.ok) {
      throw new Error('route_failed');
    }
    return response.json();
  }, [mode]);

  if (shouldHide) return null;

  const phaseTextByPhase = {
    thinking: '에이전트 분석 중',
    tool_call: '도구 실행 중',
    answering: '답변 생성 중',
    stopped: '중단됨',
    notice: '답변 생성 중',
    error: '오류 발생',
    idle: '대기 중',
  };
  const isActivelyWorking = isStreamingActive || isAgentRoute;
  const dockStatusText = isAgentRoute
    ? (phaseTextByPhase[agentStatus?.phase] || phaseTextByPhase.idle)
    : '질문하세요';
  const shouldShowChevron = hasActiveSession && !isAgentRoute;
  const pulseActive = isRouting || isAgentControlling || isStreamingActive;
  const statusDotClass = pulseActive ? 'agent-status-dot-pulse' : '';

  const submitPrompt = async (prompt) => {
    const raw = String(prompt || '').trim();
    const normalized = activePrefix ? `${activePrefix.prefix}${raw}` : raw;
    if (!normalized) return;

    const controlPayload = buildControlContextPayload(normalized);
    setIsRouting(true);
    setInlineMessage(null);

    try {
      const decision = await routePrompt(normalized, controlPayload);
      const nextDecision = decision?.decision;

      if (nextDecision === 'inline_action') {
        const matchedAction = orchestratorActionCatalog.find((item) => item.id === decision?.action_id);
        if (!matchedAction) {
          setInlineMessage({
            text: '실행 가능한 액션을 찾지 못했어요.',
            canvasPrompt: normalized,
          });
        } else {
          await executeAction(matchedAction, {
            contextPayload: controlPayload,
            prompt: normalized,
          });
        }
      } else if (nextDecision === 'open_canvas') {
        submitPromptToCanvas(decision?.canvas_prompt || normalized);
      } else if (nextDecision === 'open_chat') {
        openTutor(decision?.canvas_prompt || normalized);
      } else {
        setInlineMessage({
          text: decision?.inline_text || '자세히 보려면 캔버스를 열어주세요.',
          canvasPrompt: decision?.canvas_prompt || normalized,
        });
      }
    } catch {
      setInlineMessage({
        text: '자세한 분석은 캔버스에서 확인할 수 있어요.',
        canvasPrompt: normalized,
      });
    } finally {
      setIsRouting(false);
    }

    setInput('');
    setActivePrefix(null);
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    await submitPrompt(input || suggestedPrompt);
  };

  const handleResumeChat = () => {
    navigate('/agent', {
      state: {
        mode,
        contextPayload: buildControlContextPayload(''),
        useWebSearch: searchEnabled,
      },
    });
  };

  return (
    <div
      className="pointer-events-none fixed left-0 right-0 z-30 flex justify-center px-4 pb-2"
      style={{ bottom: `calc(${hideBottomNav ? '0px' : 'var(--bottom-nav-h,68px)'} + var(--keyboard-offset,0px))` }}
    >
      <div className="w-full max-w-mobile space-y-1.5">
        {/* 인라인 메시지 (트레이 대체 — 필요할 때만 노출) */}
        {inlineMessage?.text && (
          <div className="pointer-events-auto flex items-center justify-between gap-2 rounded-[14px] border border-[var(--agent-border,#E8EBED)] bg-white px-3 py-2 shadow-[var(--agent-shadow)]">
            <p className="min-w-0 truncate text-[12px] text-[#6B7684]">{inlineMessage.text}</p>
            {inlineMessage.canvasPrompt && (
              <button
                type="button"
                onClick={() => {
                  submitPromptToCanvas(inlineMessage.canvasPrompt);
                  setInlineMessage(null);
                }}
                className="flex-shrink-0 text-[12px] font-semibold text-[#FF6B00] active:opacity-70"
              >
                자세히
              </button>
            )}
          </div>
        )}

        {/* 볼드 입력바 */}
        <AgentControlPulse active={pulseActive}>
          <div className="pointer-events-auto relative rounded-[20px] bg-white shadow-[0_-2px_12px_rgba(0,0,0,0.06)]">
            {/* 상단 상태 라인 (항상 노출) */}
            <div className="flex items-center gap-2 border-b border-[#F2F4F6] px-3 py-1.5">
              <button
                type="button"
                onClick={hasActiveSession ? handleResumeChat : undefined}
                className={`flex min-w-0 flex-1 items-center gap-2 text-left ${hasActiveSession ? 'active:bg-[#F7F8FA]' : ''}`}
              >
                <span className={`h-1.5 w-1.5 rounded-full ${
                  isActivelyWorking ? 'bg-[#1D6FDE]' : 'bg-[#16A34A]'
                } ${statusDotClass}`} />
                <div className="min-w-0">
                  <p className={`truncate text-[12px] font-medium ${isActivelyWorking ? 'text-[#4E5968]' : 'text-[#166534]'}`}>
                    {dockStatusText}
                  </p>
                </div>
                {shouldShowChevron && (
                  <svg className="ml-auto text-[#B0B8C1]" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="m9 18 6-6-6-6" />
                  </svg>
                )}
              </button>

              <div className="ml-auto flex items-center gap-1">
                <button
                  type="button"
                  onClick={() => setSearchEnabled((prev) => !prev)}
                  className={`flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full transition-colors ${
                    searchEnabled
                      ? 'bg-[#FFF2E8] text-[#FF6B00]'
                      : 'bg-[#F2F4F6] text-[#8B95A1]'
                  }`}
                  aria-label={searchEnabled ? '인터넷 검색 켜짐' : '인터넷 검색 꺼짐'}
                  title={searchEnabled ? '인터넷 검색: 켜짐' : '인터넷 검색: 꺼짐'}
                >
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round">
                    <circle cx="12" cy="12" r="9" />
                    <path d="M3 12h18" />
                    <path d="M12 3a15 15 0 0 1 0 18" />
                    <path d="M12 3a15 15 0 0 0 0 18" />
                  </svg>
                </button>

                <button
                  type="button"
                  onClick={() => navigate('/agent/history', { state: { mode, contextPayload: buildControlContextPayload('') } })}
                  className="flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full bg-[#F2F4F6] text-[#6B7684] transition-colors active:bg-[#E8EBED]"
                  aria-label="대화 기록 보기"
                  title="대화 기록 보기"
                >
                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M12 8v5l3 2" />
                    <circle cx="12" cy="12" r="9" />
                  </svg>
                </button>
              </div>
            </div>

            {showSlashMenu && (
              <SlashCommandMenu
                query={slashQuery}
                onSelect={handleSlashCommand}
                onClose={() => { setShowSlashMenu(false); setSlashQuery(''); }}
                visible={showSlashMenu}
              />
            )}

            <form
              onSubmit={handleSubmit}
              className="flex h-12 items-center gap-2.5 px-3"
            >
              <button
                type="button"
                onClick={() => submitPrompt(suggestedPrompt)}
                className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-full bg-[#FF6B00] text-white shadow-sm active:scale-95"
                aria-label="추천 질문 사용"
              >
                <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                  <path d="M12 3l2 5 5 2-5 2-2 5-2-5-5-2 5-2 2-5z" />
                  <path d="M19 4l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
                  <path d="M5.5 15l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
                </svg>
              </button>

              <div className="flex min-w-0 flex-1 items-center gap-1.5">
                {activePrefix && (
                  <span className="inline-flex shrink-0 items-center gap-1 rounded-full border border-[#FF6B00]/20 bg-[#FFF2E8] px-2.5 py-1 text-[12px] font-semibold text-[#FF6B00]">
                    {activePrefix.label}
                    <button
                      type="button"
                      onClick={() => setActivePrefix(null)}
                      className="ml-0.5 text-[#FF6B00]/60 hover:text-[#FF6B00]"
                      aria-label="명령어 칩 제거"
                    >
                      ✕
                    </button>
                  </span>
                )}
                <input
                  type="text"
                  value={input}
                  onChange={(event) => {
                    const val = event.target.value;
                    setInput(val);
                    if (val.startsWith('/')) {
                      setShowSlashMenu(true);
                      setSlashQuery(val.slice(1));
                    } else {
                      setShowSlashMenu(false);
                      setSlashQuery('');
                    }
                  }}
                  onKeyDown={(e) => {
                    if (showSlashMenu && (e.key === 'ArrowUp' || e.key === 'ArrowDown' || e.key === 'Enter')) {
                      e.preventDefault();
                    }
                    if (e.key === 'Escape' && showSlashMenu) {
                      setShowSlashMenu(false);
                      setSlashQuery('');
                    }
                    if (e.key === 'Backspace' && !input && activePrefix) {
                      setActivePrefix(null);
                    }
                  }}
                  placeholder={activePrefix ? '내용을 입력하세요' : (input ? placeholder : suggestedPrompt)}
                  data-agent-dock-input
                  className="min-w-0 flex-1 bg-transparent text-[14px] text-[#191F28] placeholder:text-[#B0B8C1] focus:outline-none"
                  aria-label="에이전트 질문 입력"
                />
              </div>

              <button
                type="submit"
                className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-full bg-[#FF6B00] text-white shadow-sm active:scale-95"
                aria-label="질문 전송"
                disabled={isRouting}
              >
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="m12 19V5" />
                  <path d="m5 12 7-7 7 7" />
                </svg>
              </button>
            </form>
          </div>
        </AgentControlPulse>

        {pendingAction && (
          <ActionConfirmDialog
            action={pendingAction.action}
            onConfirm={() => confirmPendingAction('confirm')}
            onCancel={() => confirmPendingAction('cancel')}
            onAutoMode={() => confirmPendingAction('auto')}
          />
        )}
      </div>
    </div>
  );
}

