@import url('https://cdn.jsdelivr.net/gh/orioncactus/pretendard/dist/web/static/pretendard.css');

@tailwind base;
@tailwind components;
@tailwind utilities;

/* Light Mode (Default) - Clean White Design */
:root {
  /* Background */
  --color-background: #ffffff;
  --color-surface: #f8f9fa;
  --color-surface-elevated: #ffffff;

  /* Border */
  --color-border: #e5e7eb;
  --color-border-light: #f3f4f6;

  /* Text */
  --color-text-primary: #1a1a1a;
  --color-text-secondary: #6b7280;
  --color-text-muted: #9ca3af;

  /* Primary (Orange) */
  --color-primary: #FF6B00;
  --color-primary-hover: #e55f00;
  --color-primary-light: #FFF7ED;
  --color-primary-border: #FFEDD5;

  /* Status */
  --color-success: #10B981;
  --color-success-light: #D1FAE5;
  --color-warning: #F59E0B;
  --color-warning-light: #FEF3C7;
  --color-error: #EF4444;
  --color-error-light: #FEE2E2;
  --color-info: #3B82F6;
  --color-info-light: #DBEAFE;

  /* Typography */
  --font-sans: 'Pretendard', -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Noto Sans KR', sans-serif;

  /* Agent UI tokens – Toss-tone */
  --bottom-nav-h: 68px;
  --agent-dock-h: 88px;
  --safe-bottom-offset: calc(var(--bottom-nav-h, 68px) + var(--agent-dock-h, 88px));
  --keyboard-offset: 0px;
  --agent-radius-sm: 14px;
  --agent-radius-md: 18px;
  --agent-border: #E8EBED;
  --agent-shadow: 0 1px 4px rgba(0, 0, 0, 0.04);
  --agent-shadow-elevated: 0 2px 8px rgba(0, 0, 0, 0.06);
  --agent-bg: #FFFFFF;
  --agent-bg-page: #F7F8FA;
  --agent-text-title: 16px;
  --agent-text-body: 14px;
  --agent-text-caption: 12px;
  --agent-glow-alpha: 0.4;
  --agent-glow-blur: 34px;
  --agent-glow-spread: 0.32;

  /* Glassmorphism */
  --glass-bg: rgba(255, 255, 255, 0.7);
  --glass-border: rgba(255, 255, 255, 0.3);
  --glass-shadow: 0 8px 32px rgba(0, 0, 0, 0.06);
  --glass-header-bg: rgba(255, 255, 255, 0.72);
  --glass-nav-bg: rgba(255, 255, 255, 0.85);
}

/* Dark Mode */
.dark {
  --color-background: #0f0f0f;
  --color-surface: #1a1a1a;
  --color-surface-elevated: #262626;
  --color-border: #333333;
  --color-border-light: #262626;
  --color-text-primary: #ffffff;
  --color-text-secondary: #a3a3a3;
  --color-text-muted: #737373;
  --color-primary-light: #2d1f0f;
  --color-primary-border: #4a3320;

  /* Glassmorphism (dark) */
  --glass-bg: rgba(30, 30, 30, 0.7);
  --glass-border: rgba(255, 255, 255, 0.08);
  --glass-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
  --glass-header-bg: rgba(15, 15, 15, 0.72);
  --glass-nav-bg: rgba(15, 15, 15, 0.85);
}

@layer base {
  html {
    font-family: var(--font-sans);
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  body {
    @apply bg-background text-text-primary;
    transition: background-color 0.2s, color 0.2s;
  }

  * {
    @apply border-border;
  }
}

@layer components {
  /* Container */
  .container {
    @apply max-w-mobile mx-auto px-4;
  }

  /* Buttons */
  .btn-primary {
    @apply px-4 py-3 bg-primary text-white font-semibold rounded-xl 
           hover:bg-primary-hover active:scale-[0.98] transition-all duration-200;
  }

  .btn-secondary {
    @apply px-4 py-3 bg-surface text-text-primary font-semibold rounded-xl 
           border border-border hover:bg-border-light active:scale-[0.98] transition-all duration-200;
  }

  /* Cards */
  .card {
    @apply bg-surface-elevated rounded-card p-4 border border-border shadow-card;
  }

  .card-interactive {
    @apply hover:shadow-card-hover hover:border-primary/30 transition-all duration-200;
  }

  /* Badges */
  .badge {
    @apply inline-flex items-center px-2.5 py-1 text-xs font-semibold rounded-full;
  }

  .badge-primary {
    @apply bg-primary-light text-primary;
  }

  .badge-info {
    @apply bg-info-light text-info;
  }

  .badge-success {
    @apply bg-success-light text-success;
  }

  .badge-warning {
    @apply bg-warning-light text-warning;
  }

  .badge-error {
    @apply bg-error-light text-error;
  }

  /* Tags */
  .tag {
    @apply px-3 py-1.5 text-sm rounded-full bg-surface border border-border 
           hover:border-primary/50 transition-colors;
  }

  .tag-selected {
    @apply bg-primary-light border-primary text-primary;
  }

  /* Input */
  .input {
    @apply w-full px-4 py-3 bg-surface border border-border rounded-xl 
           focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary/20
           placeholder:text-text-muted transition-all;
  }

  /* Radio Option */
  .radio-option {
    @apply flex items-center gap-4 p-4 rounded-xl border border-border 
           cursor-pointer hover:border-primary/50 transition-all;
  }

  .radio-option-selected {
    @apply border-primary bg-primary-light;
  }

  .radio-circle {
    @apply w-5 h-5 rounded-full border-2 border-border flex-shrink-0;
  }

  .radio-circle-selected {
    @apply border-primary bg-primary;
  }

  /* Term Highlight */
  .term-highlight {
    @apply cursor-pointer
           bg-primary-light text-primary px-1 rounded font-medium
           hover:bg-primary hover:text-white transition-colors;
  }

  /* Navigation */
  .nav-bottom {
    @apply fixed bottom-0 left-0 right-0 bg-surface-elevated border-t border-border py-3 z-20;
  }

  /* Tutor Panel */
  .tutor-panel {
    @apply fixed bottom-0 left-0 right-0 bg-surface-elevated rounded-t-3xl 
           shadow-tutor-panel z-50 flex flex-col max-h-[70vh];
    transform: translateY(100%);
    transition: transform 0.3s ease-out;
  }

  .tutor-panel-open {
    transform: translateY(0);
  }

  /* App Container */
  .app-container {
    @apply min-h-screen bg-background;
  }

  /* ── Glassmorphism ── */
  .glass-card {
    background: var(--glass-bg);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border: 1px solid var(--glass-border);
    box-shadow: var(--glass-shadow);
  }

  .glass-header {
    background: var(--glass-header-bg);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
  }

  .glass-nav {
    background: var(--glass-nav-bg);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border-top: 1px solid var(--glass-border);
  }

  /* ── 용어 하이라이트 (내러티브 내 클릭 가능 용어) ── */
  .term {
    @apply cursor-pointer font-semibold px-1 py-0.5 rounded transition-colors;
    color: var(--color-primary);
    background-color: var(--color-primary-light);
  }
  .term:hover {
    @apply text-white;
    background-color: var(--color-primary);
  }

  /* ── Narrative 전용 prose 오버라이드 ── */
  .narrative-prose p {
    @apply text-sm leading-relaxed;
    color: var(--color-text-secondary);
  }
  .narrative-prose strong {
    color: var(--color-text-primary);
    @apply font-semibold;
  }
}

@layer utilities {
  .text-gain { color: #10B981; }
  .text-loss { color: #EF4444; }

  .line-limit-2 {
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
    text-overflow: ellipsis;
  }
}

/* Penguin animations */
@keyframes wobble {
  0%, 100% { transform: rotate(-5deg); }
  50% { transform: rotate(5deg); }
}
@keyframes penguinBounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-6px); }
}
.animate-wobble { animation: wobble 0.8s ease-in-out infinite; }
.animate-penguin-bounce { animation: penguinBounce 0.5s ease-in-out infinite; }

/* ── 추가 애니메이션 ── */
@keyframes shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}
@keyframes stepEnter {
  0% { opacity: 0; transform: translateY(12px); }
  100% { opacity: 1; transform: translateY(0); }
}
@keyframes pulseScale {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.05); }
}
@keyframes progressFill {
  0% { width: 0; }
  100% { width: 100%; }
}
.animate-shimmer {
  background: linear-gradient(90deg, transparent 25%, rgba(255,255,255,0.3) 50%, transparent 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s ease-in-out infinite;
}
.animate-step-enter { animation: stepEnter 0.4s ease-out forwards; }
.animate-pulse-scale { animation: pulseScale 2s ease-in-out infinite; }

@keyframes agentDotWave {
  0%, 80%, 100% {
    opacity: 0.35;
    transform: scale(0.9);
  }
  40% {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes agentDotBlink {
  0%, 100% { opacity: 0.25; }
  50% { opacity: 1; }
}

@keyframes agentControlPulse {
  0%, 100% {
    box-shadow:
      0 -12px calc(var(--agent-glow-blur) * 0.92) rgba(255, 118, 72, calc(var(--agent-glow-alpha) * 0.8)),
      0 16px calc(var(--agent-glow-blur) * 1.05) rgba(255, 118, 72, calc(var(--agent-glow-alpha) * 0.95));
  }
  50% {
    box-shadow:
      0 -14px calc(var(--agent-glow-blur) * 1.08) rgba(255, 118, 72, calc(var(--agent-glow-alpha) * 0.95)),
      0 20px calc(var(--agent-glow-blur) * 1.2) rgba(255, 118, 72, calc(var(--agent-glow-alpha) + var(--agent-glow-spread)));
  }
}

.agent-dot-wave {
  animation: agentDotWave 1.2s ease-in-out infinite;
}

.agent-dot-blink {
  animation: agentDotBlink 0.8s ease-in-out infinite;
}

.animate-agent-control-pulse {
  animation: agentControlPulse 1.6s ease-in-out infinite;
}

@keyframes agentControlPulseBlue {
  0%, 100% {
    box-shadow:
      0 -12px calc(var(--agent-glow-blur) * 0.92) rgba(29, 111, 222, calc(var(--agent-glow-alpha) * 0.8)),
      0 16px calc(var(--agent-glow-blur) * 1.05) rgba(29, 111, 222, calc(var(--agent-glow-alpha) * 0.95));
  }
  50% {
    box-shadow:
      0 -14px calc(var(--agent-glow-blur) * 1.08) rgba(29, 111, 222, calc(var(--agent-glow-alpha) * 0.95)),
      0 20px calc(var(--agent-glow-blur) * 1.2) rgba(29, 111, 222, calc(var(--agent-glow-alpha) + var(--agent-glow-spread)));
  }
}

.animate-agent-control-pulse-blue {
  animation: agentControlPulseBlue 1.6s ease-in-out infinite;
}

@keyframes agentStatusDotPulse {
  0%, 100% {
    transform: scale(0.86);
    opacity: 0.55;
  }
  50% {
    transform: scale(1.14);
    opacity: 1;
  }
}

.agent-status-dot-pulse {
  animation: agentStatusDotPulse 1s ease-in-out infinite;
  transform-origin: center;
}

/* ── 부드러운 스크롤바 ── */
.narrative-scroll::-webkit-scrollbar {
  width: 3px;
}
.narrative-scroll::-webkit-scrollbar-track {
  background: transparent;
}
.narrative-scroll::-webkit-scrollbar-thumb {
  background: var(--color-border);
  border-radius: 999px;
}
.narrative-scroll::-webkit-scrollbar-thumb:hover {
  background: var(--color-text-muted);
}

/* ═══════════════════════════════════════════════════════════════
   Phase 6: KeywordCard 시각화 스타일
   ═══════════════════════════════════════════════════════════════ */

/* 1. 헤더: 섹터 태그 + 트렌드 배지 */
.card-header {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 0.75rem;
  flex-wrap: wrap;
}

.sector-tag {
  background: var(--color-primary);
  color: white;
  padding: 0.25rem 0.5rem;
  border-radius: 4px;
  font-size: 0.75rem;
  font-weight: 600;
  line-height: 1.2;
}

.trend-badge {
  background: linear-gradient(135deg, #FF6B00 0%, #FF8C42 100%);
  color: white;
  padding: 0.25rem 0.5rem;
  border-radius: 4px;
  font-size: 0.75rem;
  line-height: 1.2;
}

/* 2. 카탈리스트 뉴스 박스 */
.catalyst-box {
  display: flex;
  gap: 0.5rem;
  padding: 0.75rem;
  background: rgba(255, 107, 0, 0.05);
  border: 1px solid rgba(255, 107, 0, 0.15);
  margin: 0.75rem 0;
  border-radius: 8px;
}

.catalyst-icon {
  font-size: 1.25rem;
  flex-shrink: 0;
}

.catalyst-title {
  font-size: 0.875rem;
  color: var(--color-text-primary);
  margin-bottom: 0.25rem;
  line-height: 1.4;
}

.catalyst-source {
  font-size: 0.75rem;
  color: var(--color-text-secondary);
}

.catalyst-link {
  font-size: 0.75rem;
  color: var(--color-primary);
  text-decoration: none;
}

.catalyst-link:hover {
  text-decoration: underline;
}

/* 4. 과거 사례 힌트 박스 */
.mirroring-hint {
  display: flex;
  gap: 0.5rem;
  padding: 0.75rem;
  background: rgba(100, 100, 255, 0.05);
  border: 1px solid rgba(100, 100, 255, 0.15);
  margin: 0.75rem 0;
  border-radius: 8px;
}

.hint-icon {
  font-size: 1.25rem;
  flex-shrink: 0;
}

.mirroring-hint p {
  font-size: 0.875rem;
  color: var(--color-text-primary);
  margin: 0;
  line-height: 1.4;
}

.similarity {
  font-size: 0.75rem;
  color: var(--color-text-secondary);
  margin-left: 0.5rem;
}

/* 5. 종목 프리뷰 */
.stocks-preview {
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--color-border);
}

.stocks-label {
  font-size: 0.75rem;
  color: var(--color-text-secondary);
  margin-bottom: 0.5rem;
  display: block;
}

.stock-chips {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.stock-chip {
  display: flex;
  align-items: center;
  gap: 0.25rem;
  padding: 0.25rem 0.5rem;
  background: var(--color-surface);
  border-radius: 4px;
  font-size: 0.75rem;
  line-height: 1.2;
}

.stock-name {
  font-weight: 600;
  color: var(--color-text-primary);
}

.stock-reason {
  color: var(--color-text-secondary);
}

.more-stocks {
  color: var(--color-text-secondary);
  font-size: 0.75rem;
  align-self: center;
}

/* 6. 오프라인 배너 */
.offline-banner {
  background: var(--color-warning-light);
  color: var(--color-text-primary);
  text-align: center;
  padding: 0.5rem;
  font-size: 0.75rem;
  font-weight: 500;
}

/* 다크모드 대응 (CSS 변수 기반이므로 자동 적용) */

/* Agent canvas markdown rendering quality */
.agent-markdown p {
  margin-top: 0.45rem;
  margin-bottom: 0.45rem;
}

.agent-markdown table {
  width: 100%;
  border-collapse: collapse;
  margin: 0.75rem 0;
  min-width: 360px;
}

.agent-markdown thead th {
  background: #f8fafc;
  color: #344054;
  font-weight: 700;
}

.agent-markdown th,
.agent-markdown td {
  border: 1px solid #e6eaf0;
  padding: 0.5rem 0.6rem;
  text-align: left;
  vertical-align: top;
  font-size: 0.82rem;
}

.agent-markdown ul,
.agent-markdown ol {
  margin-top: 0.45rem;
  margin-bottom: 0.45rem;
}

.agent-markdown pre {
  overflow-x: auto;
}

