@keyframes agentDotWave {
  0%, 80%, 100% {
    opacity: 0.35;
    transform: scale(0.9);
  }
  40% {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes agentDotBlink {
  0%, 100% { opacity: 0.25; }
  50% { opacity: 1; }
}

.agent-dot-wave {
  animation: agentDotWave 1.2s ease-in-out infinite;
}

.agent-dot-blink {
  animation: agentDotBlink 0.8s ease-in-out infinite;
}

.animate-agent-control-pulse {
  animation: agentControlPulse 1.6s ease-in-out infinite;
}

@keyframes agentControlPulseBlue {
  0%, 100% {
    box-shadow:
      0 -12px calc(var(--agent-glow-blur) * 0.92) rgba(29, 111, 222, calc(var(--agent-glow-alpha) * 0.8)),
      0 16px calc(var(--agent-glow-blur) * 1.05) rgba(29, 111, 222, calc(var(--agent-glow-alpha) * 0.95));
  }
  50% {
    box-shadow:
      0 -14px calc(var(--agent-glow-blur) * 1.08) rgba(29, 111, 222, calc(var(--agent-glow-alpha) * 0.95)),
      0 20px calc(var(--agent-glow-blur) * 1.2) rgba(29, 111, 222, calc(var(--agent-glow-alpha) + var(--agent-glow-spread)));
  }
}

.animate-agent-control-pulse-blue {
  animation: agentControlPulseBlue 1.6s ease-in-out infinite;
}

@keyframes agentStatusDotPulse {
  0%, 100% {
    transform: scale(0.86);
    opacity: 0.55;
  }
  50% {
    transform: scale(1.14);
    opacity: 1;
  }
}

.agent-status-dot-pulse {
  animation: agentStatusDotPulse 1s ease-in-out infinite;
  transform-origin: center;
}

/* ── 부드러운 스크롤바 ── */
.narrative-scroll::-webkit-scrollbar {
  width: 3px;
}
.narrative-scroll::-webkit-scrollbar-track {
  background: transparent;
}
.narrative-scroll::-webkit-scrollbar-thumb {
  background: var(--color-border);
  border-radius: 999px;
}
.narrative-scroll::-webkit-scrollbar-thumb:hover {
  background: var(--color-text-muted);
}

/* ═══════════════════════════════════════════════════════════════
   Phase 6: KeywordCard 시각화 스타일
   ═══════════════════════════════════════════════════════════════ */

/* 1. 헤더: 섹터 태그 + 트렌드 배지 */
.card-header {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 0.75rem;
  flex-wrap: wrap;
}

.sector-tag {
  background: var(--color-primary);
  color: white;
  padding: 0.25rem 0.5rem;
  border-radius: 4px;
  font-size: 0.75rem;
  font-weight: 600;
  line-height: 1.2;
}

.trend-badge {
  background: linear-gradient(135deg, #FF6B00 0%, #FF8C42 100%);
  color: white;
  padding: 0.25rem 0.5rem;
  border-radius: 4px;
  font-size: 0.75rem;
  line-height: 1.2;
}

/* 2. 카탈리스트 뉴스 박스 */
.catalyst-box {
  display: flex;
  gap: 0.5rem;
  padding: 0.75rem;
  background: rgba(255, 107, 0, 0.05);
  border: 1px solid rgba(255, 107, 0, 0.15);
  margin: 0.75rem 0;
  border-radius: 8px;
}

.catalyst-icon {
  font-size: 1.25rem;
  flex-shrink: 0;
}

.catalyst-title {
  font-size: 0.875rem;
  color: var(--color-text-primary);
  margin-bottom: 0.25rem;
  line-height: 1.4;
}

.catalyst-source {
  font-size: 0.75rem;
  color: var(--color-text-secondary);
}

.catalyst-link {
  font-size: 0.75rem;
  color: var(--color-primary);
  text-decoration: none;
}

.catalyst-link:hover {
  text-decoration: underline;
}

/* 4. 과거 사례 힌트 박스 */
.mirroring-hint {
  display: flex;
  gap: 0.5rem;
  padding: 0.75rem;
  background: rgba(100, 100, 255, 0.05);
  border: 1px solid rgba(100, 100, 255, 0.15);
  margin: 0.75rem 0;
  border-radius: 8px;
}

.hint-icon {
  font-size: 1.25rem;
  flex-shrink: 0;
}

.mirroring-hint p {
  font-size: 0.875rem;
  color: var(--color-text-primary);
  margin: 0;
  line-height: 1.4;
}

.similarity {
  font-size: 0.75rem;
  color: var(--color-text-secondary);
  margin-left: 0.5rem;
}

/* 5. 종목 프리뷰 */
.stocks-preview {
  margin-top: 0.75rem;
  padding-top: 0.75rem;
  border-top: 1px solid var(--color-border);
}

.stocks-label {
  font-size: 0.75rem;
  color: var(--color-text-secondary);
  margin-bottom: 0.5rem;
  display: block;
}

.stock-chips {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.stock-chip {
  display: flex;
  align-items: center;
  gap: 0.25rem;
  padding: 0.25rem 0.5rem;
  background: var(--color-surface);
  border-radius: 4px;
  font-size: 0.75rem;
  line-height: 1.2;
}

.stock-name {
  font-weight: 600;
  color: var(--color-text-primary);
}

.stock-reason {
  color: var(--color-text-secondary);
}

.more-stocks {
  color: var(--color-text-secondary);
  font-size: 0.75rem;
  align-self: center;
}

/* 6. 오프라인 배너 */
.offline-banner {
  background: var(--color-warning-light);
  color: var(--color-text-primary);
  text-align: center;
  padding: 0.5rem;
  font-size: 0.75rem;
  font-weight: 500;
}

/* 다크모드 대응 (CSS 변수 기반이므로 자동 적용) */

/* Agent canvas markdown rendering quality */
.agent-markdown p {
  margin-top: 0.45rem;
  margin-bottom: 0.45rem;
}

.agent-markdown table {
  width: 100%;
  border-collapse: collapse;
  margin: 0.75rem 0;
  min-width: 360px;
}

.agent-markdown thead th {
  background: #f8fafc;
  color: #344054;
  font-weight: 700;
}

.agent-markdown th,
.agent-markdown td {
  border: 1px solid #e6eaf0;
  padding: 0.5rem 0.6rem;
  text-align: left;
  vertical-align: top;
  font-size: 0.82rem;
}

.agent-markdown ul,
.agent-markdown ol {
  margin-top: 0.45rem;
  margin-bottom: 0.45rem;
}

.agent-markdown pre {
  overflow-x: auto;
}

